import React, { useState, useEffect, useRef } from 'react';

const API = 'http://localhost:5001';

function timeAgo(d) {
  const diff = Date.now() - new Date(d);
  const h = Math.floor(diff / 3600000);
  const m = Math.floor(diff / 60000);
  if (h > 0) return `${h}h ago`;
  if (m > 0) return `${m}m ago`;
  return 'just now';
}

export default function StatusViewer({ token, currentUser, onClose }) {
  const [statuses, setStatuses] = useState([]);
  const [viewing, setViewing] = useState(null); // { userIndex, statusIndex }
  const [newText, setNewText] = useState('');
  const [uploading, setUploading] = useState(false);
  const [tab, setTab] = useState('view');
  const [progress, setProgress] = useState(0);
  const progressRef = useRef(null);
  const timerRef = useRef(null);

  useEffect(() => {
    fetch(API + '/statuses', { headers: { Authorization: `Bearer ${token}` } })
      .then(r => r.json())
      .then(data => setStatuses(Array.isArray(data) ? data : []));
  }, [token]);

  // Auto-advance story every 5s
  useEffect(() => {
    if (!viewing) return;
    setProgress(0);
    clearInterval(timerRef.current);
    timerRef.current = setInterval(() => {
      setProgress(p => {
        if (p >= 100) {
          goNext();
          return 0;
        }
        return p + 1;
      });
    }, 50);
    return () => clearInterval(timerRef.current);
  }, [viewing]);

  const goNext = () => {
    if (!viewing) return;
    const user = statuses[viewing.userIndex];
    if (!user) return;
    if (viewing.statusIndex < user.statuses.length - 1) {
      setViewing(v => ({ ...v, statusIndex: v.statusIndex + 1 }));
    } else if (viewing.userIndex < statuses.length - 1) {
      setViewing({ userIndex: viewing.userIndex + 1, statusIndex: 0 });
    } else {
      setViewing(null);
    }
  };

  const goPrev = () => {
    if (!viewing) return;
    if (viewing.statusIndex > 0) {
      setViewing(v => ({ ...v, statusIndex: v.statusIndex - 1 }));
    } else if (viewing.userIndex > 0) {
      const prevUser = statuses[viewing.userIndex - 1];
      setViewing({ userIndex: viewing.userIndex - 1, statusIndex: prevUser.statuses.length - 1 });
    }
  };

  const openStatus = (userIndex, statusIndex = 0) => {
    setViewing({ userIndex, statusIndex });
    const user = statuses[userIndex];
    const st = user?.statuses[statusIndex];
    if (user && st && user.username !== currentUser.username && st._id) {
      fetch(`${API}/status/${user.username}/${st._id}/view`, {
        method: 'POST', headers: { Authorization: `Bearer ${token}` },
      }).then(r => r.json()).then(data => {
        setStatuses(prev => prev.map(u => u.username === user.username ? {
          ...u, statuses: u.statuses.map(s => s._id === st._id ? { ...s, views: data.views } : s)
        } : u));
      });
    }
  };

  const postTextStatus = async () => {
    if (!newText.trim()) return;
    setUploading(true);
    const fd = new FormData();
    fd.append('type', 'text');
    fd.append('content', newText);
    await fetch(API + '/status', { method: 'POST', headers: { Authorization: `Bearer ${token}` }, body: fd });
    setUploading(false);
    setNewText('');
    setTab('view');
    const res = await fetch(API + '/statuses', { headers: { Authorization: `Bearer ${token}` } });
    const data = await res.json();
    setStatuses(Array.isArray(data) ? data : []);
  };

  const postFileStatus = async (e, type) => {
    const file = e.target.files[0];
    if (!file) return;
    setUploading(true);
    const fd = new FormData();
    fd.append('type', type);
    fd.append('file', file);
    await fetch(API + '/status', { method: 'POST', headers: { Authorization: `Bearer ${token}` }, body: fd });
    setUploading(false);
    setTab('view');
    const res = await fetch(API + '/statuses', { headers: { Authorization: `Bearer ${token}` } });
    const data = await res.json();
    setStatuses(Array.isArray(data) ? data : []);
  };

  // Fullscreen story viewer
  if (viewing !== null) {
    const user = statuses[viewing.userIndex];
    const st = user?.statuses[viewing.statusIndex];
    if (!user || !st) { setViewing(null); return null; }

    return (
      <div className="anim-fadeIn" style={{ position: 'fixed', inset: 0, background: '#000', zIndex: 2000, display: 'flex', flexDirection: 'column' }}>
        {/* Progress bars */}
        <div style={{ display: 'flex', gap: 4, padding: '12px 16px 8px', position: 'absolute', top: 0, left: 0, right: 0, zIndex: 10 }}>
          {user.statuses.map((_, i) => (
            <div key={i} style={{ flex: 1, height: 3, borderRadius: 2, background: 'rgba(255,255,255,0.25)', overflow: 'hidden' }}>
              <div style={{
                height: '100%', background: '#fff', borderRadius: 2,
                width: i < viewing.statusIndex ? '100%' : i === viewing.statusIndex ? `${progress}%` : '0%',
                transition: i === viewing.statusIndex ? 'none' : 'none',
              }} />
            </div>
          ))}
        </div>

        {/* Header */}
        <div style={{ position: 'absolute', top: 28, left: 0, right: 0, padding: '10px 16px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', zIndex: 10 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <div style={{ width: 36, height: 36, borderRadius: '50%', background: 'linear-gradient(135deg,#6366f1,#8b5cf6)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 14, fontWeight: 700, color: '#fff', border: '2px solid rgba(255,255,255,0.3)' }}>
              {user.username[0].toUpperCase()}
            </div>
            <div>
              <div style={{ color: '#fff', fontSize: 14, fontWeight: 600 }}>
                {user.username === currentUser.username ? 'My Status' : user.username}
              </div>
              <div style={{ color: 'rgba(255,255,255,0.5)', fontSize: 11 }}>{timeAgo(st.createdAt)}</div>
            </div>
          </div>
          <button onClick={() => setViewing(null)} style={{ background: 'rgba(255,255,255,0.1)', border: 'none', color: '#fff', fontSize: 18, cursor: 'pointer', borderRadius: '50%', width: 36, height: 36, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>✕</button>
        </div>

        {/* Tap zones */}
        <div style={{ position: 'absolute', inset: 0, display: 'flex', zIndex: 5 }}>
          <div style={{ flex: 1 }} onClick={goPrev} />
          <div style={{ flex: 1 }} onClick={goNext} />
        </div>

        {/* Content */}
        <div className="anim-scaleIn" style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '80px 20px 80px' }}>
          {st.type === 'text' && (
            <div style={{ fontSize: 28, color: '#fff', fontWeight: 700, lineHeight: 1.5, textAlign: 'center', textShadow: '0 2px 12px rgba(0,0,0,0.5)' }}>{st.content}</div>
          )}
          {st.type === 'image' && (
            <img src={st.fileUrl} alt="status" style={{ maxWidth: '100%', maxHeight: '70vh', borderRadius: 12, objectFit: 'contain' }} />
          )}
          {st.type === 'video' && (
            <video src={st.fileUrl} controls autoPlay style={{ maxWidth: '100%', maxHeight: '70vh', borderRadius: 12 }} />
          )}
          {st.type === 'audio' && (
            <div style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 64, marginBottom: 20 }}>🎵</div>
              <audio src={st.fileUrl} controls autoPlay style={{ width: '100%' }} />
            </div>
          )}
        </div>

        {/* Views (own status only) */}
        {user.username === currentUser.username && (
          <div style={{ position: 'absolute', bottom: 24, left: 0, right: 0, textAlign: 'center', zIndex: 10 }}>
            <div style={{ display: 'inline-flex', alignItems: 'center', gap: 8, background: 'rgba(255,255,255,0.1)', backdropFilter: 'blur(8px)', padding: '10px 20px', borderRadius: 24, border: '1px solid rgba(255,255,255,0.15)' }}>
              <span style={{ fontSize: 18 }}>👁️</span>
              <span style={{ color: '#fff', fontSize: 14, fontWeight: 600 }}>{st.views?.length || 0} views</span>
              {st.views?.length > 0 && (
                <span style={{ color: 'rgba(255,255,255,0.5)', fontSize: 12 }}>({st.views.slice(0, 3).join(', ')}{st.views.length > 3 ? '...' : ''})</span>
              )}
            </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="anim-fadeIn" style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.75)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: 16 }} onClick={onClose}>
      <div className="anim-scaleIn glass" style={{ borderRadius: 20, width: '100%', maxWidth: 440, maxHeight: '85vh', display: 'flex', flexDirection: 'column', overflow: 'hidden', boxShadow: '0 32px 80px rgba(0,0,0,0.6)' }} onClick={e => e.stopPropagation()}>

        {/* Header */}
        <div style={{ padding: '18px 20px 14px', borderBottom: '1px solid #1e1e30', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div style={{ fontSize: 17, fontWeight: 800, color: '#e2e8f0' }}>📸 Status</div>
          <button onClick={onClose} style={{ background: 'rgba(255,255,255,0.05)', border: '1px solid #1e1e30', color: '#94a3b8', fontSize: 16, cursor: 'pointer', borderRadius: 10, width: 34, height: 34, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>✕</button>
        </div>

        {/* Tabs */}
        <div style={{ display: 'flex', gap: 6, padding: '10px 14px', borderBottom: '1px solid #1e1e30', background: '#0f0f18' }}>
          {[['view', '👁️ View'], ['add', '➕ Add Status']].map(([key, label]) => (
            <button key={key} className="tab-btn" onClick={() => setTab(key)}
              style={{ flex: 1, padding: '9px', background: tab === key ? 'linear-gradient(135deg,#6366f1,#8b5cf6)' : 'transparent', border: '1px solid ' + (tab === key ? 'transparent' : '#1e1e30'), borderRadius: 10, color: tab === key ? '#fff' : '#64748b', fontSize: 13, fontWeight: 600, cursor: 'pointer' }}>
              {label}
            </button>
          ))}
        </div>

        {/* Body */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '16px' }}>

          {/* View tab */}
          {tab === 'view' && (
            statuses.length === 0
              ? (
                <div style={{ textAlign: 'center', padding: '40px 0', color: '#334155' }}>
                  <div className="anim-float" style={{ fontSize: 40, marginBottom: 12 }}>📸</div>
                  <div style={{ fontSize: 14, fontWeight: 600 }}>No statuses yet</div>
                  <div style={{ fontSize: 12, marginTop: 4 }}>Be the first to post one!</div>
                </div>
              )
              : statuses.map((u, userIndex) => (
                <div key={u.username} style={{ marginBottom: 20 }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 10 }}>
                    <div style={{ width: 36, height: 36, borderRadius: '50%', background: 'linear-gradient(135deg,#6366f1,#8b5cf6)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 14, fontWeight: 700, color: '#fff', border: '2px solid #6366f1' }}>
                      {u.username[0].toUpperCase()}
                    </div>
                    <div>
                      <div style={{ fontSize: 13, fontWeight: 600, color: '#e2e8f0' }}>
                        {u.username === currentUser.username ? '👤 My Status' : u.username}
                      </div>
                      <div style={{ fontSize: 11, color: '#475569' }}>{u.statuses.length} update{u.statuses.length > 1 ? 's' : ''}</div>
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                    {u.statuses.map((st, i) => (
                      <div key={i} onClick={() => openStatus(userIndex, i)}
                        style={{ width: 62, height: 62, borderRadius: 12, background: '#0f0f18', border: '2px solid #6366f1', cursor: 'pointer', overflow: 'hidden', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, transition: 'transform 0.15s, box-shadow 0.15s', boxShadow: '0 0 0 0 rgba(99,102,241,0.4)' }}
                        onMouseEnter={e => { e.currentTarget.style.transform = 'scale(1.08)'; e.currentTarget.style.boxShadow = '0 0 0 3px rgba(99,102,241,0.4)'; }}
                        onMouseLeave={e => { e.currentTarget.style.transform = 'scale(1)'; e.currentTarget.style.boxShadow = '0 0 0 0 rgba(99,102,241,0.4)'; }}
                      >
                        {st.type === 'text' && <div style={{ fontSize: 9, color: '#c7d2fe', padding: 4, textAlign: 'center', overflow: 'hidden', lineHeight: 1.3 }}>{st.content?.slice(0, 20)}</div>}
                        {st.type === 'image' && <img src={st.fileUrl} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />}
                        {st.type === 'video' && <div style={{ fontSize: 22 }}>🎬</div>}
                        {st.type === 'audio' && <div style={{ fontSize: 22 }}>🎵</div>}
                      </div>
                    ))}
                  </div>
                </div>
              ))
          )}

          {/* Add tab */}
          {tab === 'add' && (
            <div className="anim-fadeUp">
              <div style={{ fontSize: 13, color: '#475569', marginBottom: 16 }}>Share a moment with your friends.</div>

              <textarea
                className="input-glow"
                style={{ width: '100%', padding: '12px 14px', background: '#0f0f18', border: '1px solid #1e1e30', borderRadius: 12, color: '#e2e8f0', fontSize: 14, outline: 'none', resize: 'none', fontFamily: 'Inter,sans-serif', boxSizing: 'border-box', marginBottom: 12, minHeight: 90, lineHeight: 1.6 }}
                placeholder="✏️ Write a text status..."
                value={newText}
                onChange={e => setNewText(e.target.value)}
              />

              {newText.trim() && (
                <button
                  className="btn-primary"
                  onClick={postTextStatus}
                  disabled={uploading}
                  style={{ width: '100%', padding: '12px', borderRadius: 11, fontSize: 14, fontWeight: 700, marginBottom: 16, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8 }}
                >
                  {uploading
                    ? <><div style={{ width: 16, height: 16, border: '2px solid rgba(255,255,255,0.3)', borderTop: '2px solid #fff', borderRadius: '50%', animation: 'spin 0.7s linear infinite' }} /> Posting...</>
                    : '✏️ Post Text Status'
                  }
                </button>
              )}

              <div style={{ fontSize: 12, color: '#334155', fontWeight: 600, textTransform: 'uppercase', letterSpacing: 0.8, marginBottom: 10 }}>Or upload media</div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                {[
                  ['image', '🖼️ Photo', '.jpg,.jpeg,.png,.gif,.webp', 'rgba(99,102,241,0.08)', 'rgba(99,102,241,0.2)', '#a5b4fc'],
                  ['video', '🎬 Video', '.mp4,.mov,.webm', 'rgba(236,72,153,0.08)', 'rgba(236,72,153,0.2)', '#f9a8d4'],
                  ['audio', '🎵 Audio', '.mp3,.wav,.ogg,.m4a', 'rgba(20,184,166,0.08)', 'rgba(20,184,166,0.2)', '#5eead4'],
                ].map(([type, label, accept, bg, border, color]) => (
                  <label key={type} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '13px 16px', background: bg, border: `1px solid ${border}`, borderRadius: 12, color, fontSize: 14, cursor: 'pointer', fontWeight: 500, transition: 'transform 0.15s' }}
                    onMouseEnter={e => e.currentTarget.style.transform = 'translateX(4px)'}
                    onMouseLeave={e => e.currentTarget.style.transform = 'translateX(0)'}
                  >
                    {label}
                    <input type="file" accept={accept} style={{ display: 'none' }} onChange={e => postFileStatus(e, type)} />
                  </label>
                ))}
              </div>

              {uploading && (
                <div style={{ textAlign: 'center', color: '#818cf8', fontSize: 13, marginTop: 16, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8 }}>
                  <div style={{ width: 16, height: 16, border: '2px solid #312e81', borderTop: '2px solid #6366f1', borderRadius: '50%', animation: 'spin 0.7s linear infinite' }} />
                  Uploading...
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
